#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<pair<int,int>> mp[100010];
struct edge
{
    int u,v,w;
    bool operator<(const edge&b)const
    {
        return w>b.w;
    }
}e[1000010];
int fa[100010],d[100010],f[100010],val[100010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
void dfs(int x,int fa=0)
{
    if(fa==0)
    {
        val[x]=-1;
    }
    d[x]=d[fa]+1;
    f[x]=fa;
    for(auto i:mp[x])
    {
        if(i.first!=fa)
        {
            val[i.first]=i.second;
            dfs(i.first,x);
        }
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&e[i].u,&e[i].v,&e[i].w);
    }
    sort(e+1,e+1+m);
    for(int i=1;i<=m;i++)
    {
        int u=e[i].u,v=e[i].v,w=e[i].w;
        if(find(u)!=find(v))
        {
            mp[u].push_back(make_pair(v,w));
            mp[v].push_back(make_pair(u,w));
            merge(u,v);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(fa[i]==i)
        {
            dfs(i);
        }
    }
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        int min1=INT_MAX;
        if(d[x]<d[y])
        {
            swap(x,y);
        }
        while(d[x]>d[y])
        {
            min1=min(min1,val[x]);
            x=f[x];
        }
        while(x!=y)
        {
            min1=min({min1,val[x],val[y]});
            x=f[x];
            y=f[y];
        }
        printf("%d\n",min1);
    }
    return 0;
}
